mapper.select:
select bdi.biz_date as bizDate, bdi.day_status as dayStatus, bdi.open_at as openAt, bdi.cutoff_at as cutoffAt, bdi.settled_at as settledAt, bdi.sla_deadline_at as slaDeadlineAt, bdi.late_count as lateCount, bdi.catchup_count as catchupCount, coalesce(stats.total_job_count, 0) as totalJobCount, coalesce(stats.success_job_count, 0) as successJobCount, coalesce(stats.failed_job_count, 0) as failedJobCount, coalesce(stats.in_flight_job_count, 0) as inFlightJobCount from batch.batch_day_instance bdi left join ( select ji.tenant_id, jd.calendar_code, ji.biz_date, count(1) as total_job_count, coalesce(sum(case when ji.instance_status = 'SUCCESS' then 1 else 0 end), 0) as success_job_count, coalesce(sum(case when ji.instance_status in ('FAILED', 'PARTIAL_FAILED', 'CANCELLED', 'TERMINATED') then 1 else 0 end), 0) as failed_job_count, coalesce(sum(case when ji.instance_status in ('CREATED', 'WAITING', 'READY', 'RUNNING') then 1 else 0 end), 0) as in_flight_job_count from batch.job_instance ji join batch.job_definition jd on jd.id = ji.job_definition_id where ji.tenant_id = #{tenantId} and jd.calendar_code = #{calendarCode}
and ji.biz_date >= #{fromBizDate}
and ji.biz_date <= #{toBizDate}
group by ji.tenant_id, jd.calendar_code, ji.biz_date ) stats on stats.tenant_id = bdi.tenant_id and stats.calendar_code = bdi.calendar_code and stats.biz_date = bdi.biz_date where bdi.tenant_id = #{tenantId} and bdi.calendar_code = #{calendarCode}
and bdi.biz_date >= #{fromBizDate}
and bdi.biz_date <= #{toBizDate}
order by bdi.biz_date desc

select count(1)
from batch.batch_day_instance bdi
where bdi.tenant_id = #{tenantId}
  and bdi.calendar_code = #{calendarCode}

  and bdi.biz_date >= #{fromBizDate}


  and bdi.biz_date <= #{toBizDate}

select distinct ji.job_code
from batch.job_instance ji
         join batch.job_definition jd on jd.id = ji.job_definition_id
where ji.tenant_id = #{tenantId}
  and jd.calendar_code = #{calendarCode}
  and ji.biz_date = #{bizDate}
  and ji.instance_status in ('FAILED', 'PARTIAL_FAILED')
order by ji.job_code asc
